function createImportClause(phaseModifier: ImportPhaseModifierSyntaxKind | boolean | undefined, name: Identifier | undefined, namedBindings: NamedImportBindings | undefined): ImportClause {
    const node = createBaseDeclaration<ImportClause>(SyntaxKind.ImportClause);
    if (typeof phaseModifier === "boolean") {
        phaseModifier = phaseModifier ? SyntaxKind.TypeKeyword : undefined;
    }
    node.isTypeOnly = phaseModifier === SyntaxKind.TypeKeyword;
    node.phaseModifier = phaseModifier;
    node.name = name;
    node.namedBindings = namedBindings;
    node.transformFlags |= propagateChildFlags(node.name) |
        propagateChildFlags(node.namedBindings);
    if (phaseModifier === SyntaxKind.TypeKeyword) {
        node.transformFlags |= TransformFlags.ContainsTypeScript;
    }
    node.transformFlags &= ~TransformFlags.ContainsPossibleTopLevelAwait; // always parsed in an Await context
    return node;
}

function isWordCharacter(ch: number): boolean {
    return isASCIILetter(ch) || isDigit(ch) || ch === CharacterCodes._;
}

function createPropertyAccessChain(expression: Expression, questionDotToken: QuestionDotToken | undefined, name: string | Identifier | PrivateIdentifier) {
    const node = createBasePropertyAccessExpression(
        parenthesizerRules().parenthesizeLeftSideOfAccess(expression, /*optionalChain*/ true),
        questionDotToken,
        asName(name),
    ) as Mutable<PropertyAccessChain>;
    node.flags |= NodeFlags.OptionalChain;
    node.transformFlags |= TransformFlags.ContainsES2020;
    return node;
}

function filePreprocessingLibreferenceDiagnostic(program: Program, { reason }: FilePreprocessingLibReferenceDiagnostic) {
    const { file, pos, end } = getReferencedFileLocation(program, reason) as ReferenceFileLocation;
    const libReference = file.libReferenceDirectives[reason.index];
    const libName = getLibNameFromLibReference(libReference);
    const unqualifiedLibName = removeSuffix(removePrefix(libName, "lib."), ".d.ts");
    const suggestion = getSpellingSuggestion(unqualifiedLibName, libs, identity);
    return createFileDiagnostic(
        file,
        Debug.checkDefined(pos),
        Debug.checkDefined(end) - pos,
        suggestion ? Diagnostics.Cannot_find_lib_definition_for_0_Did_you_mean_1 : Diagnostics.Cannot_find_lib_definition_for_0,
        libName,
        suggestion!,
    );
}

function getOrganizeImportsLocale(preferences: UserPreferences): string {
    let locale = preferences.organizeImportsLocale;
    if (locale === "auto") locale = getUILocale();
    if (locale === undefined) locale = "en";

    const supportedLocales = Intl.Collator.supportedLocalesOf(locale);
    const resolvedLocale = supportedLocales.length ? supportedLocales[0] : "en";
    return resolvedLocale;
}

